**Issue 9 — Open redirect: the redirect route must validate that the destination URL uses only http or https before redirecting.**

Read `c:\Users\chris\linkshortenerproject\app\l\[shortCode]\route.ts`.

Current content:
```typescript
import { NextRequest, NextResponse } from "next/server";
import { getLinkByShortCode } from "@/data/links";

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ shortCode: string }> },
) {
  const { shortCode } = await params;
  const link = await getLinkByShortCode(shortCode);

  if (!link) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  return NextResponse.redirect(link.url, { status: 302 });
}
```

The `link.url` is redirected to without validating that its protocol is safe. A `javascript:` or `data:` URI stored in the database could be served as a redirect target.

Fix: before the redirect, parse the URL and verify its protocol is `http:` or `https:`. If not, return a 400 error. Wrap the URL parsing in a try/catch to handle malformed URLs.

Replace the file content with:
```typescript
import { NextRequest, NextResponse } from "next/server";
import { getLinkByShortCode } from "@/data/links";

const ALLOWED_PROTOCOLS = new Set(["http:", "https:"]);

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ shortCode: string }> },
) {
  const { shortCode } = await params;
  const link = await getLinkByShortCode(shortCode);

  if (!link) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  try {
    const parsed = new URL(link.url);
    if (!ALLOWED_PROTOCOLS.has(parsed.protocol)) {
      return NextResponse.json({ error: "Invalid redirect target" }, { status: 400 });
    }
  } catch {
    return NextResponse.json({ error: "Invalid redirect target" }, { status: 400 });
  }

  return NextResponse.redirect(link.url, { status: 302 });
}
```

